controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    /* Handle malformed input and sensor timeout - always safe off */
    switch (input.kind) {
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        output.timed_out = true;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        /* Stale sensor data or no input - safe off */
        controller_set_safe_off(controller);
        break;
    }

    /* Handle valid temperature input */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        bool is_rising = (controller->last_temperature_c > 0) && 
                         (input.temperature_c >= controller->last_temperature_c);

        /* Check for stale sensor data - timeout if no valid sensor for >1000ms */
        uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
        bool is_stale = (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) && 
                        (controller->has_valid_sensor);

        /* If stale, override to safe off */
        if (is_stale) {
            controller_set_safe_off(controller);
            output.timed_out = true;
            return output;
        }

        /* Apply control policy based on temperature */
        switch (input.temperature_c) {
        case:
        case CONTROLLER_TEMP_LOW_THRESHOLD - 1: /* TEMP < 47 */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
            break;
        case CONTROLLER_TEMP_HIGH_THRESHOLD + 1: /* TEMP > 52 */
            controller_set_safe_off(controller);
            break;
        case CONTROLLER_TEMP_EARLY_OFF_THRESHOLD - 1: /* 47 <= TEMP < 50 */
            /* Hold previous safe actuator state - stay in HOLDING */
            controller->state = CONTROLLER_STATE_HOLDING;
            break;
        default: /* 50 <= TEMP <= 52 */
            if (is_rising) {
                /* Temperature rising - turn off early, hold state as HOLDING */
                controller_set_safe_off(controller);
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* Temperature not rising - preserve previous safe actuator state */
                controller->state = CONTROLLER_STATE_HOLDING;
            }
            break;
        }

        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (controller->heater_on != previous_heater_on) || 
                         (controller->state != previous_state);
    }

    return output;
}

